from datetime import datetime

from sqlalchemy import select
from sqlalchemy.orm import Session

from src.models.identity import Organization, OrganizationMembership, RefreshTokenSession, User


class IdentityRepository:
    def __init__(self, session: Session) -> None:
        self.session = session

    def get_user_by_username(self, username: str) -> User | None:
        stmt = select(User).where(User.username == username)
        return self.session.scalar(stmt)

    def get_user_by_id(self, user_id: str) -> User | None:
        stmt = select(User).where(User.id == user_id)
        return self.session.scalar(stmt)

    def create_user(self, user: User) -> User:
        self.session.add(user)
        self.session.flush()
        return user

    def create_refresh_session(self, refresh_session: RefreshTokenSession) -> RefreshTokenSession:
        self.session.add(refresh_session)
        self.session.flush()
        return refresh_session

    def find_refresh_session(self, token_hash: str) -> RefreshTokenSession | None:
        stmt = select(RefreshTokenSession).where(RefreshTokenSession.token_hash == token_hash)
        return self.session.scalar(stmt)

    def revoke_refresh_session(self, token_hash: str) -> None:
        refresh_session = self.find_refresh_session(token_hash)
        if refresh_session is not None and refresh_session.revoked_at is None:
            refresh_session.revoked_at = datetime.utcnow()
            self.session.flush()

    def create_organization(self, organization: Organization) -> Organization:
        self.session.add(organization)
        self.session.flush()
        return organization

    def find_organization_by_code(self, code: str) -> Organization | None:
        stmt = select(Organization).where(Organization.code == code)
        return self.session.scalar(stmt)

    def create_membership(self, membership: OrganizationMembership) -> OrganizationMembership:
        self.session.add(membership)
        self.session.flush()
        return membership

import base64
import hashlib
from datetime import datetime, timedelta, timezone

from cryptography.fernet import Fernet
from jose import jwt
from passlib.context import CryptContext

from src.core.config import get_settings
from src.core.constants import ACCESS_TOKEN_TYPE, REFRESH_TOKEN_TYPE

pwd_context = CryptContext(schemes=["bcrypt"], deprecated="auto")
settings = get_settings()


def hash_password(password: str) -> str:
    return pwd_context.hash(password)


def verify_password(plain_password: str, hashed_password: str) -> bool:
    return pwd_context.verify(plain_password, hashed_password)


def sha256_text(value: str) -> str:
    return hashlib.sha256(value.encode("utf-8")).hexdigest()


def build_access_token(user_id: str) -> tuple[str, int]:
    now = datetime.now(timezone.utc)
    expire = now + timedelta(minutes=settings.jwt_access_token_expire_minutes)
    payload = {
        "sub": user_id,
        "iss": settings.jwt_issuer,
        "aud": settings.jwt_audience,
        "iat": int(now.timestamp()),
        "exp": int(expire.timestamp()),
        "type": ACCESS_TOKEN_TYPE,
    }
    token = jwt.encode(payload, settings.jwt_secret_key, algorithm=settings.jwt_algorithm)
    return token, settings.jwt_access_token_expire_minutes * 60


def build_refresh_token(user_id: str) -> str:
    now = datetime.now(timezone.utc)
    expire = now + timedelta(days=settings.jwt_refresh_token_expire_days)
    payload = {
        "sub": user_id,
        "iss": settings.jwt_issuer,
        "aud": settings.jwt_audience,
        "iat": int(now.timestamp()),
        "exp": int(expire.timestamp()),
        "type": REFRESH_TOKEN_TYPE,
    }
    return jwt.encode(payload, settings.jwt_secret_key, algorithm=settings.jwt_algorithm)


def decode_token(token: str) -> dict[str, object]:
    return jwt.decode(
        token,
        settings.jwt_secret_key,
        algorithms=[settings.jwt_algorithm],
        issuer=settings.jwt_issuer,
        audience=settings.jwt_audience,
    )


def build_field_encryptor() -> Fernet:
    key_bytes = hashlib.sha256(settings.encryption_key.encode("utf-8")).digest()
    fernet_key = base64.urlsafe_b64encode(key_bytes)
    return Fernet(fernet_key)


field_encryptor = build_field_encryptor()


def encrypt_sensitive(raw_text: str) -> str:
    return field_encryptor.encrypt(raw_text.encode("utf-8")).decode("utf-8")


def decrypt_sensitive(encrypted_text: str) -> str:
    return field_encryptor.decrypt(encrypted_text.encode("utf-8")).decode("utf-8")

from fastapi import APIRouter, Depends, Header
from sqlalchemy.orm import Session

from src.api.v1.dependencies import get_current_user_id, get_session
from src.schemas.auth import (
    LoginRequest,
    LogoutRequest,
    PasswordResetRequest,
    RefreshRequest,
    RegisterRequest,
    TokenPairResponse,
)
from src.schemas.user import UserProfileResponse
from src.services.auth_service import AuthService

router = APIRouter(prefix="/auth")


@router.post("/register", response_model=UserProfileResponse)
def register(request: RegisterRequest, session: Session = Depends(get_session)) -> UserProfileResponse:
    service = AuthService(session)
    user = service.register_user(request)
    return UserProfileResponse(
        id=user.id,
        username=user.username,
        display_name=user.display_name,
        email=user.email,
    )


@router.post("/login", response_model=TokenPairResponse)
def login(
    request: LoginRequest,
    session: Session = Depends(get_session),
    user_agent: str | None = Header(default=None),
    x_forwarded_for: str | None = Header(default=None),
) -> TokenPairResponse:
    service = AuthService(session)
    return service.login_user(request, user_agent=user_agent, ip_address=x_forwarded_for)


@router.post("/refresh", response_model=TokenPairResponse)
def refresh(
    request: RefreshRequest,
    session: Session = Depends(get_session),
    user_agent: str | None = Header(default=None),
    x_forwarded_for: str | None = Header(default=None),
) -> TokenPairResponse:
    service = AuthService(session)
    return service.refresh(request.refresh_token, user_agent=user_agent, ip_address=x_forwarded_for)


@router.post("/logout")
def logout(request: LogoutRequest, session: Session = Depends(get_session)) -> dict[str, bool]:
    service = AuthService(session)
    service.logout(request.refresh_token)
    return {"success": True}


@router.post("/password/reset")
def reset_password(request: PasswordResetRequest, session: Session = Depends(get_session)) -> dict[str, bool]:
    service = AuthService(session)
    service.reset_password(request)
    return {"success": True}


@router.get("/me", response_model=UserProfileResponse)
def me(
    current_user_id: str = Depends(get_current_user_id),
    session: Session = Depends(get_session),
) -> UserProfileResponse:
    service = AuthService(session)
    user = service.repository.get_user_by_id(current_user_id)
    if user is None:
        raise ValueError("Current user missing")
    return UserProfileResponse(
        id=user.id,
        username=user.username,
        display_name=user.display_name,
        email=user.email,
    )

